const navigate = useNavigate();

const handleSubmit = async (data) => {
  // In live mode, this submits to ADSP Form Service
  // Generate reference number from response
  const referenceNumber = `APP-${Date.now()}`;
  navigate('/confirmation', { state: { referenceNumber } });
};

return (
  <GoabOneColumnLayout>
    <GoabPageBlock width="704px">
